args.sparql:
SELECT ?song ?songLabel WHERE {
  wd:Q166164 wdt:P175 ?album .
  ?album wdt:P31 wd:Q262188 .
  ?album p:P1263 ?certStmt .
  ?certStmt ps:P1263 wd:Q395542 ;
             pq:P451 wd:Q38 ;
             pq:P1547 ?certValue .
  FILTER (?certValue * 50000 >= 280000)
  ?album wdt:P1087 ?song .
  ?song rdfs:label ?songLabel .
  FILTER(lang(?songLabel) = 'en')
}
